 * First end-to-end demo of the PL/SW compiler.
 * Declares a static string and prints it to UART. */

DCL MSG CHAR(20) INIT('Hello from PL/SW!');

/* UART_PUTCHAR -- write one byte to UART data register */
UART_PUTCHAR: PROC(CH INT(24)) OPTIONS(NAKED);
    ASM DO;
        "push    fp";
        "push    r2";
        "push    r1";
        "mov     fp,sp";
        "la      r2,16711936";
        "lw      r0,9(fp)";
        "sb      r0,0(r2)";
        "mov     sp,fp";
        "pop     r1";
        "pop     r2";
        "pop     fp";
        "jmp     (r1)";
    END;
END;

/* UART_PUTS -- print a null-terminated string followed by newline */
UART_PUTS: PROC(S PTR) OPTIONS(NAKED);
    ASM DO;
        "push    fp";
        "push    r2";
        "push    r1";
        "mov     fp,sp";
        "lw      r2,9(fp)";
    END;
    /* loop: load byte, test, print */
    ASM DO;
        "lbu     r0,0(r2)";
        "ceq     r0,z";
        "brt     _UART_PUTS_DONE";
        "push    r2";
        "lc      r2,3";
        "sub     sp,r2";
        "sw      r0,0(sp)";
        "la      r2,_UART_PUTCHAR";
        "jal     r1,(r2)";
        "lc      r2,3";
        "add     sp,r2";
        "pop     r2";
        "lc      r0,1";
        "add     r2,r0";
        "bra     _UART_PUTS+5";
    END;
    ASM DO;
        "_UART_PUTS_DONE:";
        "lc      r0,10";
        "lc      r2,3";
        "sub     sp,r2";
        "sw      r0,0(sp)";
        "la      r2,_UART_PUTCHAR";
        "jal     r1,(r2)";
        "lc      r2,3";
        "add     sp,r2";
        "mov     sp,fp";
        "pop     r1";
        "pop     r2";
        "pop     fp";
        "jmp     (r1)";
    END;
END;

/* MAIN -- entry point */
MAIN: PROC;
    CALL UART_PUTS(ADDR(MSG));
END;

