                idx = sym_lookup("STEP");
                uart_putstr("  STEP(local): offset=");
                print_int(sym_offset[idx]);
                uart_putchar(10);

                sym_exit_scope();
                break;
            }
            child = nd_next[child];
        }

        layout_print_frame();
    } else {
        uart_puts("  PARSE ERROR");
    }

    /* Test 12: multiple static allocations track correctly */
    uart_puts("--- static tracking ---");
    arena_init();
