    /* Also load it back to verify large-offset load path */
    cg_expr(nd_ident("BIG"));
    uart_putstr(emit_output());
    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

    /* Summary */
    uart_putstr("assign codegen errors: ");
    print_int(errs);
    uart_putchar(10);
}

