    /* Test 7: %DEFINE with value, bare name condition */
    uart_puts("Test 7: bare name condition (shorthand for DEFINED)");
    arena_init();
    src = "%DEFINE FEATURE;"
          "%IF FEATURE;"
          "DCL OK INT(24);"
