    src = "%DEFINE TARGET COR24;"
          "%IF TARGET = COR24;"
          "DCL MATCH INT(24);"
          "%ENDIF;";
    lex_init(src, str_len(src));
    lex_scan(); /* DCL */
    lex_scan(); /* MATCH */
    if (!str_eq_nocase(cur_text, "MATCH")) {
        uart_putstr("  FAIL: expected MATCH, got ");
        uart_puts(cur_text);
        errs = errs + 1;
    } else {
        uart_puts("  OK: value equality true, got MATCH");
