        if (!str_find(out, "push     fp")) {
            uart_puts("  FAIL: regular proc should have prologue");
            errs = errs + 1;
        }
        /* Should have nop from ASM block */
        if (!str_find(out, "nop")) {
            uart_puts("  FAIL: missing nop from ASM block");
            errs = errs + 1;
        }
    }

    /* Summary */
    uart_putstr("inline asm codegen errors: ");
    print_int(errs);
    uart_putchar(10);
}

