            uart_puts(tok_name(cur_type));
            errs = errs + 1;
        } else {
            uart_puts("  OK: second token is DO");
        }
        lex_scan(); /* ';' */
        lex_scan(); /* string literal */
        if (cur_type != TOK_STRING) {
            uart_putstr("  FAIL: expected STRING, got ");
            uart_puts(tok_name(cur_type));
            errs = errs + 1;
