/* COR24 UART_PUTS runtime: print null-terminated string + newline */
void emit_runtime_uart_puts(void) {
    emit_line("        .globl  _UART_PUTS");
    emit_line("_UART_PUTS:");
    emit_line("        push    fp");
    emit_line("        push    r2");
    emit_line("        push    r1");
    emit_line("        mov     fp,sp");
    emit_line("        lw      r2,9(fp)");
    emit_line("_uart_puts_loop:");
    emit_line("        lbu     r0,0(r2)");
    emit_line("        ceq     r0,z");
    emit_line("        brt     _uart_puts_done");
    /* call UART_PUTCHAR(r0) -- save r2, push arg, call, clean, restore */
    emit_line("        push    r2");
    emit_line("        push    r0");
    emit_line("        la      r0,_UART_PUTCHAR");
    emit_line("        jal     r1,(r0)");
    emit_line("        add     sp,3");
    emit_line("        pop     r2");
    emit_line("        lc      r0,1");
    emit_line("        add     r2,r0");
    emit_line("        bra     _uart_puts_loop");
    emit_line("_uart_puts_done:");
    /* print newline */
    emit_line("        lc      r0,10");
    emit_line("        push    r0");
    emit_line("        la      r0,_UART_PUTCHAR");
    emit_line("        jal     r1,(r0)");
    emit_line("        add     sp,3");
    emit_line("        mov     sp,fp");
    emit_line("        pop     r1");
    emit_line("        pop     r2");
    emit_line("        pop     fp");
    emit_line("        jmp     (r1)");
    emit_nl();
}

