        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);
        /* Should call GETVAL then store r0 into X */
