            uart_puts("  FAIL: missing BUF in body");
            errs = errs + 1;
        } else {
            uart_puts("  OK: body contains BUF");
        }

        /* Body should have IF */
        if (!str_find(result, "IF")) {
            uart_puts("  FAIL: missing IF in body");
            errs = errs + 1;
        } else {
            uart_puts("  OK: body contains IF");
