        uart_putstr("  FAIL: expected DCL, got ");
        uart_puts(tok_name(cur_type));
        errs = errs + 1;
    } else {
        uart_puts("  OK: true branch emits DCL");
    }

    /* Test 2: false branch is skipped */
    uart_puts("Test 2: false %IF branch skipped");
    arena_init();
