        fsize = layout_proc(proc);

        idx = sym_lookup("DST");
        uart_putstr("  DST(PTR): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("VAL");
        uart_putstr("  VAL(BYTE): offset=");
        print_int(sym_offset[idx]);
