        uart_putstr(out);
        if (!str_find(out, "push    r0")) {
            uart_puts("  FAIL: missing push r0 for arg");
            errs = errs + 1;
        }
        if (!str_find(out, "la      r2,_PRINT")) {
            uart_puts("  FAIL: missing call target");
            errs = errs + 1;
        }
        if (!str_find(out, "add     sp,3")) {
            uart_puts("  FAIL: missing stack cleanup");
