    src = "%DEFINE MODE DEBUG;"
          "%IF MODE = RELEASE;"
          "DCL WRONG INT(24);"
          "%ELSE;"
          "DCL RIGHT INT(24);"
          "%ENDIF;";
    lex_init(src, str_len(src));
