    tc_init();
    uart_putstr("  ptr->int arg: ");
    uart_puts(type_compat_arg(TYPE_PTR, TYPE_INT24) ? "OK" : "FAIL");
    tc_init();
    uart_putstr("  rec->int arg: ");
    uart_puts(type_compat_arg(TYPE_RECORD, TYPE_INT24) ? "FAIL" : "OK");
