            errs = errs + 1;
        }
        /* Must have jmp to skip else block after then */
        if (!str_find(out, "jmp     L")) {
            uart_puts("  FAIL: missing jmp (skip else after then)");
            errs = errs + 1;
        }
        /* Must have at least 2 labels (else and end) */
