    } else {
        /* Now invoke: ?GETMAIN(LENGTH(256), ADDRESS(BUF)) */
        src = "?GETMAIN(LENGTH(256), ADDRESS(BUF))";
        lex_init(src, str_len(src));
        lex_scan(); /* gets TOK_QUESTION */

        result = mac_invoke();
