            uart_putstr(cur_text);
            uart_puts("'");
            errs = errs + 1;
        } else {
            uart_puts("  OK: string = 'mvi r0,256'");
        }
    }

    /* Summary */
    uart_putstr("macro expansion errors: ");
    print_int(errs);
    uart_putchar(10);
}

