        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);

        if (!str_find(out, "_MIXED:")) {
            uart_puts("  FAIL: missing proc label _MIXED");
            errs = errs + 1;
